// Group derivations for the artifacts list page.
// Pure, regex-based; safe to run on every render.

export type GroupBy = import('$lib/urlState').GroupBy;

// folderOf("docs/helix/01-frame/prd.md") => "docs/helix/01-frame"
// folderOf("README.md") => "/"
const FOLDER_RE = /^(.*)\/[^/]+$/;
export function folderOf(path: string): string {
	const m = path.match(FOLDER_RE);
	if (!m) return '/';
	return m[1] || '/';
}

// prefixOf("docs/helix/01-frame/prd.md") => "docs"
// prefixOf("/library/personas/x.md") => "library"
const PREFIX_RE = /^\/?([^/]+)/;
export function prefixOf(path: string): string {
	const m = path.match(PREFIX_RE);
	return m ? m[1] : '';
}

// Workflow stage derivation. Matches the canonical HELIX-style numbered
// stage segment (e.g. 01-frame, 02-design) anywhere in the path. Returns
// the bare stage name lowercased, or null when no stage segment is found.
const STAGE_RE = /(?:^|\/)\d{2}-([a-z][a-z0-9-]*)(?:\/|$)/i;
export function workflowStageOf(path: string): string | null {
	const m = path.match(STAGE_RE);
	return m ? m[1].toLowerCase() : null;
}

// Whether the workflow-stage axis should be shown for the given paths.
// The axis is hidden when no artifact in view has a derivable stage.
export function axisAvailable(paths: Iterable<string>): boolean {
	for (const p of paths) {
		if (workflowStageOf(p) !== null) return true;
	}
	return false;
}

export interface Groupable {
	path: string;
	mediaType: string;
}

// Generic, project-neutral label for the workflow-stage axis.
export const WORKFLOW_STAGE_LABEL = 'Workflow stage';

export const WORKFLOW_STAGE_FALLBACK_LABEL = 'Unstaged';

export function groupKey(item: Groupable, by: GroupBy): string {
	switch (by) {
		case 'folder':
			return folderOf(item.path);
		case 'prefix':
			return prefixOf(item.path);
		case 'mediaType':
			return item.mediaType || 'unknown';
		case 'workflowStage':
			return workflowStageOf(item.path) ?? WORKFLOW_STAGE_FALLBACK_LABEL;
	}
}

export function groupItems<T extends Groupable>(
	items: T[],
	by: GroupBy
): { key: string; items: T[] }[] {
	const buckets = new Map<string, T[]>();
	for (const it of items) {
		const k = groupKey(it, by);
		const arr = buckets.get(k);
		if (arr) arr.push(it);
		else buckets.set(k, [it]);
	}
	return Array.from(buckets.entries())
		.sort(([a], [b]) => a.localeCompare(b))
		.map(([key, items]) => ({ key, items }));
}

export const GROUP_BY_LABELS: Record<GroupBy, string> = {
	folder: 'Folder',
	prefix: 'Prefix',
	mediaType: 'Media type',
	workflowStage: WORKFLOW_STAGE_LABEL
};

export const GROUP_BY_OPTIONS: { value: GroupBy; label: string }[] = [
	{ value: 'folder', label: GROUP_BY_LABELS.folder },
	{ value: 'prefix', label: GROUP_BY_LABELS.prefix },
	{ value: 'mediaType', label: GROUP_BY_LABELS.mediaType },
	{ value: 'workflowStage', label: WORKFLOW_STAGE_LABEL }
];

export function groupCountLabel(
	groupCount: number,
	loadedCount: number,
	hasNextPage: boolean
): string {
	return hasNextPage ? `${groupCount} of ${loadedCount} loaded` : `${groupCount}`;
}

import type { GroupBy } from './grouping';

export interface GroupByStorage {
	getItem(key: string): string | null;
	setItem(key: string, value: string): void;
	removeItem(key: string): void;
}

export function groupByStorageKey(projectId: string): string {
	return `artifacts:groupBy:${projectId}`;
}

export function readPersistedGroupBy(storage: GroupByStorage, projectId: string): GroupBy | null {
	const raw = storage.getItem(groupByStorageKey(projectId));
	if (raw === 'folder' || raw === 'prefix' || raw === 'mediaType' || raw === 'workflowStage') {
		return raw;
	}
	return null;
}

export function writePersistedGroupBy(
	storage: GroupByStorage,
	projectId: string,
	groupBy: GroupBy
): void {
	storage.setItem(groupByStorageKey(projectId), groupBy);
}

import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';
import { readState } from '$lib/urlState';
import type { GroupBy } from './grouping';

export const ARTIFACTS_QUERY = gql`
	query Artifacts(
		$projectID: ID!
		$first: Int
		$after: String
		$mediaType: String
		$search: String
		$sort: ArtifactSort
		$staleness: String
		$phase: String
		$prefix: [String!]
	) {
		artifacts(
			projectID: $projectID
			first: $first
			after: $after
			mediaType: $mediaType
			search: $search
			sort: $sort
			staleness: $staleness
			phase: $phase
			prefix: $prefix
		) {
			edges {
				node {
					id
					path
					title
					mediaType
					staleness
				}
				cursor
				snippet
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`;

export interface ArtifactNode {
	id: string;
	path: string;
	title: string;
	mediaType: string;
	staleness: string;
}

export interface ArtifactEdge {
	node: ArtifactNode;
	cursor: string;
	snippet?: string | null;
}

export interface PageInfo {
	hasNextPage: boolean;
	endCursor: string | null;
}

export interface ArtifactConnection {
	edges: ArtifactEdge[];
	pageInfo: PageInfo;
	totalCount: number;
}

interface ArtifactsResult {
	artifacts: ArtifactConnection;
}

export const PAGE_SIZE = 50;

export const SORT_OPTIONS = [
	{ value: 'PATH', label: 'Path' },
	{ value: 'TITLE', label: 'Title' },
	{ value: 'MODIFIED', label: 'Last modified' },
	{ value: 'DEPS_COUNT', label: 'Dependency count' },
	{ value: 'ID', label: 'ID' }
] as const;

export type ArtifactSort = (typeof SORT_OPTIONS)[number]['value'];
export const DEFAULT_SORT: ArtifactSort = 'PATH';

const SORT_VALUES = new Set(SORT_OPTIONS.map((o) => o.value));

export function parseSort(raw: string | null): ArtifactSort {
	return raw && SORT_VALUES.has(raw as ArtifactSort) ? (raw as ArtifactSort) : DEFAULT_SORT;
}

export const STALENESS_OPTIONS = ['fresh', 'stale', 'missing'] as const;
export type Staleness = (typeof STALENESS_OPTIONS)[number];
const STALENESS_SET = new Set<string>(STALENESS_OPTIONS);

export function parseStaleness(raw: string | null): Staleness | null {
	return raw && STALENESS_SET.has(raw) ? (raw as Staleness) : null;
}

export const load: PageLoad = async ({ params, url, fetch }) => {
	const state = readState(url.searchParams);
	const hasGroupByParam = url.searchParams.has('groupBy');
	const mediaType = state.mediaType;
	const q = state.q;
	const groupBy: GroupBy = state.groupBy;
	const sort = parseSort(state.sort);
	const staleness = parseStaleness(state.staleness);
	const phase = state.phase;
	const prefix = state.prefix;

	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
		projectID: params.projectId,
		first: PAGE_SIZE,
		mediaType: mediaType ?? undefined,
		search: q ? q : undefined,
		sort,
		staleness: staleness ?? undefined,
		phase: phase ?? undefined,
		prefix: prefix.length > 0 ? prefix : undefined
	});
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifacts: data.artifacts,
		mediaType,
		q,
		groupBy,
		sort,
		staleness,
		phase,
		prefix,
		hasGroupByParam
	};
};

import { describe, it, expect } from 'vitest';
import {
	folderOf,
	prefixOf,
	workflowStageOf,
	axisAvailable,
	groupItems,
	groupCountLabel,
	WORKFLOW_STAGE_LABEL
} from './grouping';

describe('folderOf', () => {
	it('returns parent dir for nested paths', () => {
		expect(folderOf('docs/helix/01-frame/prd.md')).toBe('docs/helix/01-frame');
	});
	it('returns "/" for top-level files', () => {
		expect(folderOf('README.md')).toBe('/');
	});
	it('handles leading slash', () => {
		expect(folderOf('/a/b/c.md')).toBe('/a/b');
	});
});

describe('prefixOf', () => {
	it('returns the first path segment', () => {
		expect(prefixOf('docs/helix/x.md')).toBe('docs');
	});
	it('strips leading slash', () => {
		expect(prefixOf('/library/personas/x.md')).toBe('library');
	});
	it('returns the whole name when there is no slash', () => {
		expect(prefixOf('README.md')).toBe('README.md');
	});
});

describe('workflowStageOf', () => {
	it('extracts a HELIX-style numbered stage segment', () => {
		expect(workflowStageOf('docs/helix/01-frame/prd.md')).toBe('frame');
		expect(workflowStageOf('docs/helix/04-build/spec.md')).toBe('build');
	});
	it('returns null when no stage segment is present', () => {
		expect(workflowStageOf('library/personas/x.md')).toBeNull();
		expect(workflowStageOf('README.md')).toBeNull();
	});
});

describe('axisAvailable', () => {
	it('is true when at least one path has a stage', () => {
		expect(axisAvailable(['README.md', 'docs/helix/02-design/x.md'])).toBe(true);
	});
	it('is false when no path has a stage', () => {
		expect(axisAvailable(['README.md', 'library/x.md'])).toBe(false);
	});
});

describe('groupItems', () => {
	const items = [
		{ path: 'docs/a.md', mediaType: 'text/markdown' },
		{ path: 'docs/b.md', mediaType: 'text/markdown' },
		{ path: 'src/x.svg', mediaType: 'image/svg+xml' }
	];
	it('groups by folder', () => {
		const groups = groupItems(items, 'folder');
		expect(groups.map((g) => g.key)).toEqual(['docs', 'src']);
		expect(groups[0].items).toHaveLength(2);
	});
	it('groups by mediaType', () => {
		const groups = groupItems(items, 'mediaType');
		expect(groups.map((g) => g.key)).toEqual(['image/svg+xml', 'text/markdown']);
	});
	it('groups by prefix', () => {
		const groups = groupItems(items, 'prefix');
		expect(groups.map((g) => g.key)).toEqual(['docs', 'src']);
	});
	it('groups by workflow stage and keeps unstaged items together', () => {
		const groups = groupItems(
			[
				{ path: 'docs/helix/01-frame/a.md', mediaType: 'text/markdown' },
				{ path: 'README.md', mediaType: 'text/markdown' }
			],
			'workflowStage'
		);
		expect(groups).toHaveLength(2);
		expect(groups.find((g) => g.key === 'frame')?.items).toHaveLength(1);
		expect(groups.find((g) => g.key === 'Unstaged')?.items).toHaveLength(1);
	});
});

describe('label constants', () => {
	it('uses generic Workflow stage label', () => {
		expect(WORKFLOW_STAGE_LABEL).toBe('Workflow stage');
	});
});

describe('groupCountLabel', () => {
	it('describes loaded pagination honestly when more pages exist', () => {
		expect(groupCountLabel(3, 12, true)).toBe('3 of 12 loaded');
	});

	it('falls back to the simple count when pagination is complete', () => {
		expect(groupCountLabel(3, 3, false)).toBe('3');
	});
});

import { describe, it, expect } from 'vitest';
import { readPersistedGroupBy, writePersistedGroupBy } from './persistence';

class MemoryStorage {
	private items = new Map<string, string>();

	getItem(key: string): string | null {
		return this.items.get(key) ?? null;
	}

	setItem(key: string, value: string): void {
		this.items.set(key, value);
	}

	removeItem(key: string): void {
		this.items.delete(key);
	}
}

describe('artifacts groupBy persistence', () => {
	it('round-trips the selected groupBy per project', () => {
		const storage = new MemoryStorage();
		writePersistedGroupBy(storage, 'project-a', 'workflowStage');
		expect(readPersistedGroupBy(storage, 'project-a')).toBe('workflowStage');
	});

	it('keeps project keys isolated', () => {
		const storage = new MemoryStorage();
		writePersistedGroupBy(storage, 'project-a', 'prefix');
		expect(readPersistedGroupBy(storage, 'project-b')).toBeNull();
	});

	it('ignores unknown stored values', () => {
		const storage = new MemoryStorage();
		storage.setItem('artifacts:groupBy:project-a', 'nope');
		expect(readPersistedGroupBy(storage, 'project-a')).toBeNull();
	});
});

import { describe, it, expect } from 'vitest'
import { createRequestSequence, runLatest } from './searchFetcher'

function deferred<T>(): { promise: Promise<T>; resolve: (v: T) => void; reject: (e: unknown) => void } {
	let resolve!: (v: T) => void
	let reject!: (e: unknown) => void
	const promise = new Promise<T>((res, rej) => {
		resolve = res
		reject = rej
	})
	return { promise, resolve, reject }
}

describe('createRequestSequence', () => {
	it('marks only the latest token as current', () => {
		const seq = createRequestSequence()
		const a = seq.next()
		const b = seq.next()
		expect(seq.isCurrent(a)).toBe(false)
		expect(seq.isCurrent(b)).toBe(true)
	})

	it('invalidate() drops all in-flight tokens', () => {
		const seq = createRequestSequence()
		const t = seq.next()
		seq.invalidate()
		expect(seq.isCurrent(t)).toBe(false)
	})

	it('returns false for a never-issued token', () => {
		const seq = createRequestSequence()
		expect(seq.isCurrent(0)).toBe(false)
		expect(seq.isCurrent(99)).toBe(false)
	})
})

describe('runLatest', () => {
	it('returns the value when no newer call superseded it', async () => {
		const seq = createRequestSequence()
		const result = await runLatest(seq, async () => 42)
		expect(result).toEqual({ stale: false, value: 42 })
	})

	it('drops the older response when a newer call resolves first', async () => {
		// Simulates the artifacts search race: user types "fo", then "foo"; the
		// "fo" response (page 1) arrives AFTER "foo" page 1 has already painted.
		const seq = createRequestSequence()
		const older = deferred<string>()
		const newer = deferred<string>()

		const olderPromise = runLatest(seq, () => older.promise)
		const newerPromise = runLatest(seq, () => newer.promise)

		newer.resolve('foo-results')
		const newerOutcome = await newerPromise
		expect(newerOutcome).toEqual({ stale: false, value: 'foo-results' })

		older.resolve('fo-results')
		const olderOutcome = await olderPromise
		expect(olderOutcome).toEqual({ stale: true })
	})

	it('drops a response invalidated mid-flight (e.g. search changed)', async () => {
		const seq = createRequestSequence()
		const d = deferred<string>()
		const promise = runLatest(seq, () => d.promise)
		// User typed a new query; caller invalidates the in-flight loadMore.
		seq.invalidate()
		d.resolve('page2')
		expect(await promise).toEqual({ stale: true })
	})

	it('treats successive paginated calls (page 1, page 2) as non-stale when uncontended', async () => {
		// Correctness past page 1: when the user has not changed the search
		// while paging, both responses are honored in order.
		const seq = createRequestSequence()
		type Page = { edges: number[]; cursor: string | null }
		const page1: Page = { edges: [1, 2, 3], cursor: 'c1' }
		const page2: Page = { edges: [4, 5, 6], cursor: null }

		const r1 = await runLatest(seq, async () => page1)
		expect(r1).toEqual({ stale: false, value: page1 })

		const r2 = await runLatest(seq, async () => page2)
		expect(r2).toEqual({ stale: false, value: page2 })
	})

	it('swallows errors from stale responses but propagates fresh errors', async () => {
		const seq = createRequestSequence()
		const stale = deferred<never>()
		const stalePromise = runLatest(seq, () => stale.promise)
		seq.next() // newer call supersedes
		stale.reject(new Error('boom'))
		expect(await stalePromise).toEqual({ stale: true })

		const seq2 = createRequestSequence()
		await expect(runLatest(seq2, async () => { throw new Error('x') })).rejects.toThrow('x')
	})
})

// Shared URL-state helper for list views (artifacts, etc.).
// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
// staleness, phase, prefix, filters.*) while preserving any unrelated keys,
// including ?back=.

export type GroupBy = 'folder' | 'prefix' | 'mediaType' | 'workflowStage';

// Reserved facet URL keys (TD-029 facet contract):
//   q          — full-text search query (single)
//   mediaType  — media-type filter (single, supports X/* wildcard)
//   staleness  — staleness filter (single)
//   phase      — HELIX phase filter (single)
//   prefix     — id-prefix filter (multi: comma-separated)
//   sort       — sort key (single)
// groupBy is a Story-5 categorization axis (not a filter) and travels in
// the same URL but does NOT narrow results.
const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort', 'staleness', 'phase', 'prefix']);
const FILTER_PREFIX = 'filter.';

export interface ListURLState {
	q: string;
	mediaType: string | null;
	groupBy: GroupBy;
	sort: string | null;
	staleness: string | null;
	phase: string | null;
	prefix: string[];
	filters: Record<string, string>;
}

export const DEFAULT_GROUP_BY: GroupBy = 'folder';

function parseGroupBy(raw: string | null): GroupBy {
	if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder' || raw === 'workflowStage')
		return raw;
	return DEFAULT_GROUP_BY;
}

export function readState(params: URLSearchParams): ListURLState {
	const filters: Record<string, string> = {};
	for (const [k, v] of params.entries()) {
		if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v;
	}
	const rawPrefix = params.get('prefix');
	const prefix = rawPrefix
		? rawPrefix
				.split(',')
				.map((s) => s.trim())
				.filter((s) => s.length > 0)
		: [];
	return {
		q: params.get('q') ?? '',
		mediaType: params.get('mediaType'),
		groupBy: parseGroupBy(params.get('groupBy')),
		sort: params.get('sort'),
		staleness: params.get('staleness'),
		phase: params.get('phase'),
		prefix,
		filters
	};
}

// writeState mutates a copy of `params` with the patch applied. Unrelated
// keys (including `back`) are preserved. Empty/null values delete the key.
export function writeState(params: URLSearchParams, patch: Partial<ListURLState>): URLSearchParams {
	const next = new URLSearchParams(params);

	if ('q' in patch) {
		if (patch.q) next.set('q', patch.q);
		else next.delete('q');
	}
	if ('mediaType' in patch) {
		if (patch.mediaType) next.set('mediaType', patch.mediaType);
		else next.delete('mediaType');
	}
	if ('groupBy' in patch) {
		if (patch.groupBy && patch.groupBy !== DEFAULT_GROUP_BY) next.set('groupBy', patch.groupBy);
		else next.delete('groupBy');
	}
	if ('sort' in patch) {
		if (patch.sort) next.set('sort', patch.sort);
		else next.delete('sort');
	}
	if ('staleness' in patch) {
		if (patch.staleness) next.set('staleness', patch.staleness);
		else next.delete('staleness');
	}
	if ('phase' in patch) {
		if (patch.phase) next.set('phase', patch.phase);
		else next.delete('phase');
	}
	if ('prefix' in patch) {
		const arr = patch.prefix ?? [];
		if (arr.length > 0) next.set('prefix', arr.join(','));
		else next.delete('prefix');
	}
	if ('filters' in patch && patch.filters) {
		// Replace only the filter.* keys; leave everything else intact.
		for (const k of Array.from(next.keys())) {
			if (k.startsWith(FILTER_PREFIX)) next.delete(k);
		}
		for (const [k, v] of Object.entries(patch.filters)) {
			if (v) next.set(FILTER_PREFIX + k, v);
		}
	}

	return next;
}

// Build a back-href that captures the current pathname + relevant search.
export function backHref(pathname: string, params: URLSearchParams): string {
	const s = params.toString();
	return s ? `${pathname}?${s}` : pathname;
}

